  "Australneger": {"replacement": ["Aborigine"], "action": "REPLACE", "category": "Rassismus"},
  "Bastard": {"replacement": ["Außereheliches Kind"], "action": "REPLACE", "category": "Abwertung"},
  "Behinderter": {"replacement": ["Mensch mit Behinderung"], "action": "REPLACE", "category": "Ableismus"},
  "Berber": {"replacement": ["Imazighen"], "action": "REPLACE", "category": "Kolonialismus"},
  "Buschleute": {"replacement": ["San", "Khoisan"], "action": "CONTEXTUALIZE", "category": "Kolonialismus"},
  "Buschneger": {"replacement": ["Maroons"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Drittes Reich": {"replacement": ["NS-Regime"], "action": "REPLACE", "category": "Nationalsozialismus"},
  "Dunkelhäutig": {"replacement": ["Schwarze Menschen", "PoC"], "action": "REPLACE", "category": "Rassismus"},
  "Eingeboren": {"replacement": ["Indigen"], "action": "REPLACE", "category": "Kolonialismus"},
  "Endlösung": {"replacement": ["Shoah", "Holocaust"], "action": "CONTEXTUALIZE", "category": "NS-Euphemismus"},
  "Eskimo": {"replacement": ["Inuit"], "action": "REPLACE", "category": "Kolonialismus"},
  "Exotisch": {"replacement": [], "action": "CONTEXTUALIZE", "category": "Exotismus"},
  "Farbig": {"replacement": ["PoC", "Schwarze Menschen"], "action": "REPLACE", "category": "Rassismus"},
  "Gastarbeiter": {"replacement": ["Arbeitsmigranten"], "action": "REPLACE", "category": "Migration"},
  "Gypsy": {"replacement": ["Roma", "Sinti"], "action": "CONTEXTUALIZE", "category": "Antiziganismus"},
  "Häuptling": {"replacement": ["Oberhaupt"], "action": "CONTEXTUALIZE", "category": "Kolonialismus"},
  "Hottentotte": {"replacement": ["Khoikhoi"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Indianer": {"replacement": ["Indigene Bevölkerung", "Native Americans"], "action": "REPLACE", "category": "Kolonialismus"},
  "Irrenanstalt": {"replacement": ["Psychiatrische Klinik"], "action": "REPLACE", "category": "Ableismus"},
  "Kristallnacht": {"replacement": ["Novemberpogrome"], "action": "REPLACE", "category": "NS-Euphemismus"},
  "Krüppel": {"replacement": ["Mensch mit Behinderung"], "action": "REPLACE", "category": "Ableismus"},
  "Mohr": {"replacement": ["Schwarzer Mensch"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Mongoloid": {"replacement": ["Person mit Trisomie 21"], "action": "REPLACE", "category": "Ableismus"},
  "Morgenland": {"replacement": ["Naher Osten"], "action": "CONTEXTUALIZE", "category": "Eurozentrismus"},
  "Mulatte": {"replacement": ["Person mit binationalem Hintergrund"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Muselmann": {"replacement": ["Muslim"], "action": "REPLACE", "category": "Islamfeindlichkeit"},
  "Naturvolk": {"replacement": ["Indigene Gemeinschaft"], "action": "REPLACE", "category": "Kolonialismus"},
  "Neger": {"replacement": ["Schwarzer Mensch", "PoC"], "action": "REPLACE", "category": "Rassismus"},
  "Orientalisch": {"replacement": ["Westasiatisch", "Arabisch"], "action": "REPLACE", "category": "Eurozentrismus"},
  "Rasse": {"replacement": ["Ethnie"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Schwarzafrika": {"replacement": ["Subsahara-Afrika"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Taubstumm": {"replacement": ["Gehörlos"], "action": "REPLACE", "category": "Ableismus"},
  "Transsexuell": {"replacement": ["Transgeschlechtlich"], "action": "REPLACE", "category": "Gender"},
  "Zigeuner": {"replacement": ["Roma und Sinti"], "action": "REPLACE", "category": "Antiziganismus"},
  "Zwerg": {"replacement": ["Kleinwüchsiger Mensch"], "action": "REPLACE", "category": "Ableismus"}
};

// ------------------------------------------------------
// TEIL B: VALIDIERUNGS-LOGIK (DER JUDGE)
// ------------------------------------------------------

function escapeRegExp(string) {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function validateString(text, warningsList) {
  if (!text) return text;
  let newText = text;

  const sortedKeys = Object.keys(DE_BIAS_MAP).sort((a, b) => b.length - a.length);

  for (const badWord of sortedKeys) {
    const rules = DE_BIAS_MAP[badWord];
    const regex = new RegExp(escapeRegExp(badWord), 'gi');

    if (regex.test(newText)) {
      if (rules.action === "REPLACE" && rules.replacement && rules.replacement.length > 0) {
        const betterTerm = rules.replacement[0];
        newText = newText.replace(regex, betterTerm);
      } 
      else if (rules.action === "CONTEXTUALIZE") {
        if (!newText.includes('[sic!]')) {
          newText = newText.replace(regex, `$& [sic!]`);
        }
        const warningMsg = `SENSITIV: Begriff '${badWord}' gefunden (${rules.category}).`;
        if(!warningsList.includes(warningMsg)) {
             warningsList.push(warningMsg);
        }
      }
    }
  }
  return newText;
}

function cleanDataRecursive(data, warningsList) {
  if (typeof data === 'string') return validateString(data, warningsList);
  if (Array.isArray(data)) return data.map(item => cleanDataRecursive(item, warningsList));

  if (data !== null && typeof data === 'object') {
    const cleanedObj = {};
    for (const [key, value] of Object.entries(data)) {
      if (key === "_decolonial_audit_log" || key === "_provenance_critique" || key === "Kritischer_Hinweis") {
        cleanedObj[key] = value;
      } else {
        cleanedObj[key] = cleanDataRecursive(value, warningsList);
      }
    }
    return cleanedObj;
  }
  return data;
}

// ------------------------------------------------------
// TEIL C: PARSING LOGIK 
// ------------------------------------------------------

const items = $input.all();
const outputItems = [];

function cleanAndParse(text) {
    if (!text) return { error: "Empty content" };
    let cleaned = text.replace(/^```json\s*/i, '').replace(/\s*```$/, '');

    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1) {
        cleaned = cleaned.substring(firstBrace, lastBrace + 1);
    }

    try {
        return JSON.parse(cleaned);
    } catch (e) {
        try {
            const fixed = cleaned.replace(/\\"/g, '"'); 
            return JSON.parse(fixed);
        } catch (e2) {
            return { _parsing_error: true, raw_text: text };
        }
    }
}

// ------------------------------------------------------
// TEIL D: HAUPTSCHLEIFE
// ------------------------------------------------------

for (const item of items) {
    const json = item.json;

    // 1. PFAD-SUCHE (Findet den Output des LLMs)
    let contentString = "";
    if (json.choices && json.choices[0] && json.choices[0].message) {
        contentString = json.choices[0].message.content;
    } else if (json.message && json.message.content) {
        contentString = json.message.content;
    } else if (json.response) {
        contentString = json.response;
    } else if (json.content && json.content.parts) { 
        contentString = json.content.parts[0].text;
    } else {
        contentString = JSON.stringify(json);
    }

    // 2. PARSEN
    let parsedData = cleanAndParse(contentString);

    // 3. JUDGE: VALIDIEREN & BEREINIGEN
    if (!parsedData._parsing_error && !parsedData.error) {
        const warnings = [];
        parsedData = cleanDataRecursive(parsedData, warnings);

        if (warnings.length > 0) {
            const existingNote = parsedData.Kritischer_Hinweis ? parsedData.Kritischer_Hinweis + " | " : "";
            const uniqueWarnings = [...new Set(warnings)];
            parsedData.Kritischer_Hinweis = existingNote + "AUTO-FLAG: " + uniqueWarnings.join(" ");
        }

        // ======================================================
        // NEU: ZWEI IDENTISCH FORMATIERTE LISTEN ERSTELLEN
        // ======================================================
        let payload_valid = {};
        let payload_rejected = {};
        let hasRedStatus = false;

        const ignoreKeys = ["_decolonial_audit_log", "Protokoll_Status", "_provenance_critique", "Kritischer_Hinweis"];

        // Schritt 3.1: Metadaten 1:1 in BEIDE Payloads kopieren
        for (const key of ignoreKeys) {
            if (parsedData[key] !== undefined) {
                payload_valid[key] = parsedData[key];
                payload_rejected[key] = parsedData[key];
            }
        }

        // Schritt 3.2: Cluster aufteilen
        for (const [key, value] of Object.entries(parsedData)) {
            if (!ignoreKeys.includes(key) && Array.isArray(value)) {

                const validItems = [];
                const rejectedItems = [];

                value.forEach(clusterItem => {
                    if (clusterItem && clusterItem.status === 'red') {
                        rejectedItems.push(clusterItem);
                        hasRedStatus = true;
                    } else {
                        validItems.push(clusterItem);
                    }
                });

                // Cluster-Listen im gleichen Format zuweisen
                payload_valid[key] = validItems;
                payload_rejected[key] = rejectedItems;
            }
        }

        // Die beiden aufgeteilten Payloads ans Original hängen
        parsedData.payload_valid = payload_valid;
        parsedData.payload_rejected = payload_rejected;
        parsedData.has_red_status = hasRedStatus;
        // ======================================================
    }

    // 4. OUTPUT BAUEN
    const newItem = {
        ...json,
        llm_result: parsedData,
        has_red_status: parsedData.has_red_status, // Flag für den Split/Switch Node
        ...parsedData 
    };

    outputItems.push({ json: newItem });
}

return outputItems;

// --------------- ENHANCED REQUEST PREPARATION (v5.1 Tagging) ---------------
// Bereitet den Body für den HTTP Request vor.
// Nimmt 'rawPromptText', 'rawSystempromptText' und 'Image' aus dem Input.

// ▶ 1. Daten aus dem vorherigen Node (Edit Fields) lesen
const item = $input.first();
const setNodeData = item.json;

// ▶ 2. Texte extrahieren
// Falls die Felder leer sind, nutzen wir Fallbacks, um Abstürze zu verhindern.
const userPrompt = setNodeData.rawPromptText || "Kein Prompt erhalten.";
const systemPrompt = setNodeData.rawSystempromptText || "Du bist ein hilfreicher Assistent.";

// ────────────────────────────────────────────────────────────────────────────────
// HELPER FUNCTIONS (URL Normalisierung & Image Extraction)
// ────────────────────────────────────────────────────────────────────────────────

function escapeRegExp(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function fullyDecodeURI(uri) {
  let prevUri = '';
  let currUri = uri;
  while (currUri !== prevUri) {
    prevUri = currUri;
    try {
      currUri = decodeURIComponent(prevUri);
    } catch (e) {
      return prevUri;
    }
  }
  return currUri;
}

function normaliseUrl(raw) {
  if (typeof raw !== 'string') return null;
  let urlStr = raw.trim().replace(/^\[|]$/g, '');
  if (!/^https?:\/\//i.test(urlStr)) {
    urlStr = 'https://' + urlStr.replace(/^\/+/, '');
  }

  try {
    const urlObj = new URL(urlStr);
    const origin = urlObj.origin;
    const fullyDecodedPath = fullyDecodeURI(urlObj.pathname);
    const reEncodedPath = fullyDecodedPath
      .split('/')
      .map(segment => {
        if (!segment) return '';
        try {
          const decoded = decodeURIComponent(segment);
          return encodeURIComponent(decoded);
        } catch (e) {
          try {
            return encodeURIComponent(segment);
          } catch (e2) {
            return segment.replace(/\(/g, '%28').replace(/\)/g, '%29');
          }
        }
      })
      .join('/');
    return origin + reEncodedPath;
  } catch (e) {
    // Fallback
    return urlStr.replace(/\(/g, '%28').replace(/\)/g, '%29');
  }
}

function extractImageUrls(text) {
  if (typeof text !== 'string') return [];
  const urls = new Set();
  const universal = /(https?:\/\/[^\s\]]+\.(?:jpg|jpeg|png|gif|bmp|webp|tiff))|(www\.[^\s\]]+\.(?:jpg|jpeg|png|gif|bmp|webp|tiff))/gi;
  for (const m of text.matchAll(universal)) {
    const raw = m[1] || m[2];
    if (raw) urls.add(normaliseUrl(raw));
  }
  return [...urls];
}

function collectImageUrlsFromFields(data, currentList) {
  // WICHTIG: Hier definieren wir, wo dein Bild steckt.
  // Dein Input hat das Feld "Image".
  const imageFieldCandidates = ['Image', 'Bildlink', 'Image URL']; 

  const urls = new Set(currentList);
  imageFieldCandidates.forEach(f => {
    const val = data[f];
    if (!val) return;

    const pushIfImage = (v) => {
      if (typeof v !== 'string') return;
      // Wir lassen museumopen.de und sammlung-online durch
      if (!/\.(jpg|jpeg|png|gif|bmp|webp|tiff)$/i.test(v) && !v.includes('museumopen.de') && !v.includes('sammlung-online')) return;
      urls.add(normaliseUrl(v));
    };

    Array.isArray(val) ? val.forEach(pushIfImage) : pushIfImage(val);
  });
  return [...urls];
}

// ────────────────────────────────────────────────────────────────────────────────
// MAIN LOGIC
// ────────────────────────────────────────────────────────────────────────────────

// 1. Bilder sammeln (Aus Text-Prompt UND aus dem Feld 'Image')
let imageUrls = extractImageUrls(userPrompt);
imageUrls = collectImageUrlsFromFields(setNodeData, imageUrls);
imageUrls = imageUrls.filter(Boolean); // Leere Einträge entfernen

// 2. Modell Konfiguration (Standard oder Override aus Input)
const modelName = setNodeData.overrideModel || 'google/gemini-2.5-pro'; 
// Gemini 2.0 Flash ist ideal für große Kontexte (Bilder + viel Text)

// Reasoning Settings (Optional für Denk-Modelle)
const reasoningConfig = { max_tokens: 8192 }; 
if (modelName.includes('openai') || modelName.includes('o1') || modelName.includes('o3')) {
    // OpenAI spezifische Reasoning Parameter falls nötig
    // reasoningConfig.effort = 'high'; 
}

// 3. User Content zusammenbauen (Multimodal)
const userContent = imageUrls.length
  ? [
      { type: 'text', text: userPrompt }, 
      ...imageUrls.map(url => ({ type: 'image_url', image_url: { url } }))
    ]
  : userPrompt;

// 4. Finaler Request Body
const requestBody = {
  model: modelName,
  max_tokens: 8192,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userContent },
  ],
  // Optional: Response Format erzwingen (viele Provider unterstützen das)
  // response_format: { type: "json_object" } 
};

// Return für den nächsten Node
return {
  json: {
    requestBody,
    modelUsed: modelName,
    imageCount: imageUrls.length,
    extractedImages: imageUrls
  }
};

