function escapeRegExp(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function fullyDecodeURI(uri) {
  let prevUri = '';
  let currUri = uri;
  while (currUri !== prevUri) {
    prevUri = currUri;
    try {
      currUri = decodeURIComponent(prevUri);
    } catch (e) {
      return prevUri;
    }
  }
  return currUri;
}

function normaliseUrl(raw) {
  if (typeof raw !== 'string') return null;
  let urlStr = raw.trim().replace(/^\[|]$/g, '');
  if (!/^https?:\/\//i.test(urlStr)) {
    urlStr = 'https://' + urlStr.replace(/^\/+/, '');
  }

  try {
    const urlObj = new URL(urlStr);
    const origin = urlObj.origin;
    const fullyDecodedPath = fullyDecodeURI(urlObj.pathname);
    const reEncodedPath = fullyDecodedPath
      .split('/')
      .map(segment => {
        if (!segment) return '';
        try {
          const decoded = decodeURIComponent(segment);
          return encodeURIComponent(decoded);
        } catch (e) {
          try {
            return encodeURIComponent(segment);
          } catch (e2) {
            return segment.replace(/\(/g, '%28').replace(/\)/g, '%29');
          }
        }
      })
      .join('/');
    return origin + reEncodedPath;
  } catch (e) {
    try {
      const dec = fullyDecodeURI(urlStr);
      return encodeURI(dec).replace(/\(/g, '%28').replace(/\)/g, '%29');
    } catch (err) {
      return urlStr.replace(/\(/g, '%28').replace(/\)/g, '%29');
    }
  }
}

function extractImageUrls(text) {
  if (typeof text !== 'string') return [];
  const urls = new Set();
  const universal = /(https?:\/\/[^\s\]]+\.(?:jpg|jpeg|png|gif|bmp|webp|tiff))|(www\.[^\s\]]+\.(?:jpg|jpeg|png|gif|bmp|webp|tiff))/gi;
  for (const m of text.matchAll(universal)) {
    const raw = m[1] || m[2];
    if (raw) urls.add(normaliseUrl(raw));
  }
  return [...urls];
}

