function getReasoningConfig(model) {
  const m = model.toLowerCase();
  const REASONING_BUDGET = 4096;

  if (m.startsWith('google/') || m.includes('gemini')) return { max_tokens: REASONING_BUDGET };
  if (m.startsWith('anthropic/')) return { max_tokens: REASONING_BUDGET };
  if (m.startsWith('xai/') || m.includes('grok')) return { effort: 'high' };
  if (m.startsWith('openai/') || m.includes('gpt-') || m.includes('o3')) return { effort: 'high' };
  if (m.startsWith('perplexity/') || m.includes('sonar') || m.startsWith('deepseek/') || m.includes('deepseek') || m.startsWith('mistralai/') || m.includes('magistral') || m.startsWith('qwen/') || m.includes('qwen3')) {
    return { max_tokens: REASONING_BUDGET };
  }
  return { enabled: true };
}

function wantsIncludeThoughts(model) {
  const m = model.toLowerCase();
  return m.startsWith('google/') || m.includes('gemini');
}

